import React, { useEffect, useState } from "react";
import {
  Table,
  TableBody,
  TableCaption,
  TableCell,
  TableHead,
  TableHeader,
  TableRow,
} from "./ui/Table";
import { useNavigate } from "react-router-dom";

const BookList = () => {
  const [books, setBooks] = useState([]);
  const navigate = useNavigate();
  useEffect(() => {
    fetch("http://localhost:3000/api/book")
      .then((response) => response.json())
      .then((data) => setBooks(data))
      .catch((error) => console.error("erro for the data fetching ", error));
  }, []);

  const handleClick = (id) => {
    console.log("you click" + id);
    navigate(`/bookShow/${id}`);
  };
  return (
    <div className="w-full h-screen flex justify-center items-center text-center">
      <div className="w-[50vw] h-[50vh]">
        <Table className="flex text-cen">
          <TableCaption>book List</TableCaption>
          <TableHeader>
            <TableRow className="bg-gray-600 ">
              <TableHead className="w-[100px]">ID</TableHead>
              <TableHead>Title</TableHead>
              <TableHead>description</TableHead>
              <TableHead className="text-right">Nombre des page</TableHead>
            </TableRow>
          </TableHeader>
          <TableBody>
            {books.map((book) => (
              <TableRow
                key={book._id}
                className="cursor-pointer"
                onClick={() => handleClick(book._id)}
              >
                <TableCell className="font-medium">{book._id}</TableCell>
                <TableCell>{book.title}</TableCell>
                <TableCell>{book.description}</TableCell>
                <TableCell className="text-right">{book.page}</TableCell>
              </TableRow>
            ))}
          </TableBody>
        </Table>
      </div>
    </div>
  );
};

export default BookList;
